WD=[-30, 33, 20, -33, 37, 8, 36, -12, -41, 25, 6, 39, 22, -21, -16, 59, -26, 42, -5, 34, 18, -21, -20, 3, 6, 10, -12, -4, 4, -53, 9, -13, 9, -127, -44, -29, -36, 88, -26, -90, 15, -17, -6, -26, 27, 46, -36, -41, 5, -44, -2, -16, 42, 33, 10, -1, 0, 54, -14, 2, 32, -23, -29, 51, -4, 9, 52, -30, 13, 33, 46, -1, -10, 64, 10, -2, 22, -83, 15, 58, -15, 76, -13, -9, 49, -27, -6, 28, 13, 16, -32, -12, -10, -12, 10, 24, -47, 43, 6, 30, 16, 6, 9, 53, 27, -47, 53, 19, 2, -4, -45, -41, -4, 7, 16, 34, 20, -31, -6, 1, -20, 22, -9, -27, 3, -22, -64, 79]

BD=[90, -5, -12, 0, -11, 127, 0, -25]



WO=[54, -12, -19, -118, 84, 110, -6, 50, -2, -41, -13, 4, -45, 5, 16, 73, -31, -76, -33, -39, 40, -127, 53, 88]

BO=[127, -60, -67]



H=16
IN=4
DH=8
NC=3
SL=8



def _sig(x):

    return 1.0/(1.0+math.exp(
        -max(-20,min(20,x))
    ))



def _tanh(x):

    return math.tanh(
        max(-20,min(20,x))
    )



def _relu(x):

    return x if x>0 else 0.0



def lstm(seq,W,B,scaleW,scaleB,input_size):


    h=[0.0]*H
    c=[0.0]*H


    for x in seq:


        xh=x+h


        stride=input_size+H


        g=[]


        for gate in range(4):

            for j in range(H):

                soma=0


                for i in range(
                    len(xh)
                ):

                    soma += (
                        W[
                         (gate*H+j)*stride+i
                        ]
                        *
                        xh[i]
                    )


                soma = (
                    soma*scaleW
                    +
                    B[
                     gate*H+j
                    ]*scaleB
                )


                g.append(soma)



        nh=[]
        nc=[]


        for j in range(H):


            iv=_sig(
                g[j]
            )

            fv=_sig(
                g[H+j]
            )

            ov=_sig(
                g[2*H+j]
            )

            gv=_tanh(
                g[3*H+j]
            )


            cv=(
                fv*c[j]
                +
                iv*gv
            )


            nc.append(cv)


            nh.append(
                ov*_tanh(cv)
            )


        h=nh
        c=nc



    return h





def predict(features):


    h1=lstm(
        features,
        W1,
        B1,
        SW1,
        SB1,
        IN
    )


    h2=lstm(
        [h1]*SL,
        W2,
        B2,
        SW2,
        SB2,
        H
    )



    d=[]


    for k in range(DH):

        s=0


        for j in range(H):

            s += (
                WD[k*H+j]
                *
                h2[j]
            )


        d.append(
            _relu(
                s*SWD
                +
                BD[k]*SBD
            )
        )



    z=[]


    for k in range(NC):

        s=0


        for j in range(DH):

            s += (
                WO[k*DH+j]
                *
                d[j]
            )


        z.append(
            s*SWO
            +
            BO[k]*SBO
        )



    m=max(z)


    e=[
        math.exp(v-m)
        for v in z
    ]


    total=sum(e)


    return [
        x/total
        for x in e
    ]




LABELS=[
    "NORMAL",
    "SUSPEITO",
    "BLOQUEADO"
]



def classify(features):


    p=predict(features)


    idx=p.index(
        max(p)
    )


    return (
        LABELS[idx],
        round(
            p[idx]*100
        )
    )

